import APIDot from "apidot";

const client = new APIDot({
  apiKey: process.env.APIDOT_API_KEY,
});

const request = {
  model: "gpt-image-2",
  callback_url: "https://your-domain.com/callback",
  input: {
    prompt: "一张银色意式咖啡机的高端产品图，纯白棚拍背景，光线真实，细节清晰",
    size: "1024x1024",
    n: 1
  }
};

const response = await client.generate({
  endpoint: "/api/generate/submit",
  ...request,
});

sample.python:
import os
from apidot import APIDot

client = APIDot(api_key=os.environ["APIDOT_API_KEY"])

request = {
    "model": "gpt-image-2",
    "callback_url": "https://your-domain.com/callback",
    "input": {
        "prompt": "一张银色意式咖啡机的高端产品图，纯白棚拍背景，光线真实，细节清晰",
        "size": "1024x1024",
        "n": 1
    }
}

response = client.generate(
    endpoint="/api/generate/submit",
    **request
)
